import numpy as np
from numba import jit

@jit(nopython=True)
def harmonic_mean(x, y, alpha=0.6):
    if x <= 0 or y <= 0:
        return max(x, y)
    return 1.0 / (alpha / x + (1 - alpha) / y)

def select_machine(machine_process_times, machine_available_time):
    if len(machine_process_times) == 0:
        machine_id = 0
        return machine_id

    machines = np.array([mp[0] for mp in machine_process_times], dtype=np.int32)
    process_times = np.array([mp[1] for mp in machine_process_times], dtype=np.int32)

    avail_times = np.array([machine_available_time[m] for m in machines], dtype=np.int32)
    earliest_completion = avail_times + process_times

    # Calculate loads as busy time (assuming it's machine_available_time)
    loads = avail_times.astype(np.float64)

    max_ec = np.max(earliest_completion)
    min_ec = np.min(earliest_completion)
    max_load = np.max(loads)
    min_load = np.min(loads)

    # Normalize earliest_completion (lower better)
    if max_ec - min_ec > 0:
        ec_norm = (earliest_completion - min_ec) / (max_ec - min_ec)
    else:
        ec_norm = np.zeros(len(earliest_completion))

    # Normalize loads (higher load is worse, so inverse normalized load)
    if max_load - min_load > 0:
        load_norm = 1.0 - (loads - min_load) / (max_load - min_load)
    else:
        load_norm = np.ones(len(loads))

    scores = np.empty(len(machines), dtype=np.float64)
    alpha = 0.6
    for i in range(len(machines)):
        scores[i] = harmonic_mean(ec_norm[i] + 1e-8, load_norm[i] + 1e-8, alpha)

    idx = np.argmin(scores)
    machine_id = machines[idx]
    return machine_id
